var e=[{id:`L2_1`,type:`dialog`,speaker:`DREKA_DOLL_NULL_NULL`,text:{KOREA:`제가 처음 이곳에 왔을 때 약속해 주셨죠?`,JPN:`私が初めてこの場所に来たときに約束してくれましたよね？ `,ENG:`You promised me when I first came here, remember?`,TWN:`你還記得我剛到這裡的時候，你答應過我什麼嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DREKA_DOLL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`DREKA_DOLL_NULL_NULL`,text:{KOREA:`인간의 감정을 가르쳐 주시겠다고… 아직 배울 것이 많이 남았으니까 좀 더 함께 할 수 있겠네요.`,JPN:`人間の感情を教えてくれるって……まだ教わることがたくさん残っているからもう少し一緒にいられますね。`,ENG:`That you'll teach me about human emotions... I still have a lot to learn, so I think I'll stay with you a little longer.`,TWN:`你說要教會我人類的情感…而我還有很多要學的，所以我們可以再多相處一段時間。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DREKA_DOLL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`DREKA_DOLL_NULL_NULL`,text:{KOREA:`후훗, 너무 설레는 기분… 어라?`,JPN:`ふふっ、とても胸が高鳴る気分……あれ？`,ENG:`Haha. I feel all tingly inside... Huh?`,TWN:`嘻嘻，好興奮…喔？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DREKA_DOLL_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};